python3 -c "
import json
topics = {
    'NFL': ['NFL', 'Super Bowl', 'Week 18', 'Seahawks', '49ers', 'Bears', 'Eagles', 'Steelers', 'Ravens', 'Broncos', 'Patriots', 'Panthers', 'Buccaneers'],
    'AFCON': ['AFCON', 'Africa Cup', 'Senegal', 'Sudan', 'Mali', 'Tunisia'],
    'Iran': ['Iran'],
    'Ukraine': ['Zelensky', 'Zelenskyy'],
    'Trump': ['Trump'],
    'New Year attack': ['New Year', 'Mint Hill'],
    'Greenland': ['Greenland'],
}
counts = {}
with open('articles/2026/01/03/articles.jsonl') as f:
    for line in f:
        a = json.loads(line)
        title = a.get('title','') or ''
        for topic, kws in topics.items():
            for kw in kws:
                if kw.lower() in title.lower():
                    counts[topic] = counts.get(topic, 0) + 1
                    break
for topic, count in sorted(counts.items(), key=lambda x: -x[1]):
    print(f'{topic}: {count}')
"
